1054→    public static void removeRecentlyPickedSiteId(Integer localId) {
1055→        ArrayList<Integer> currentIds = getRecentlyPickedSiteIds(MAX_RECENTLY_PICKED_SITES_TO_SAVE);
1056→
1057→        int index = currentIds.indexOf(localId);
1058→        if (index > -1) {
1059→            currentIds.remove(index);
1060→            String idsAsString = TextUtils.join(",", currentIds);
1061→            setString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, idsAsString);
1062→        }
