1010→    private static ArrayList<Integer> getRecentlyPickedSiteIds(int limit) {
1011→        String idsAsString = getString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, "");
1012→        String[] items = idsAsString.split(",");
1013→
1014→        ArrayList<Integer> siteIds = new ArrayList<>();
1015→        for (String item : items) {
1016→            siteIds.add(StringUtils.stringToInt(item));
1017→            if (siteIds.size() == limit) {
1018→                break;
1019→            }
1020→        }
1021→
1022→        return siteIds;
